#region v4.0 — Option 31: Export Diagnostics
function Invoke-ExportDiagnosticsMenu {
    [CmdletBinding()] param()
    Write-Header 'EXPORT DIAGNOSTICS (Option 31)'
    if ($script:Findings.Count -eq 0) { Write-DiagWarning 'No findings to export. Run some checks first.'; return }
    Write-Info "Findings in memory: $($script:Findings.Count)"
    $fmt  = Get-ValidatedChoice -Prompt 'Format (J=JSON, N=NDJSON, C=CSV, S=SARIF, A=All)' -ValidChoices @('J','N','C','S','A')
    $base = Read-Host "Output folder (Enter for $script:DefaultLogPath)"
    if (-not $base) { $base = $script:DefaultLogPath }
    if (-not (Test-Path $base)) { New-Item -Path $base -ItemType Directory -Force | Out-Null }
    Export-FindingsToFile -Format $fmt -OutputPath $base
}

function Export-FindingsToFile {
    <#
    .SYNOPSIS
        Serialises $script:Findings to JSON, NDJSON, CSV, or SARIF-lite.
    #>
    [CmdletBinding()] param(
        [Parameter(Mandatory)][ValidateSet('J','N','C','S','A','JSON','NDJSON','CSV','SARIF','All','Both','HTML')] [string]$Format,
        [Parameter(Mandatory)][string]$OutputPath
    )
    $stamp = Get-Date -Format 'yyyyMMdd_HHmmss'
    $envelope = [ordered]@{
        '$schema' = 'https://github.com/Infra-Scripts/wstt/schemas/wstt-findings-v1.schema.json'
        schema   = 'wstt-findings-v1'
        meta     = $script:RunMetadata
        endedUtc = (Get-Date).ToUniversalTime().ToString('o')
        findings = $script:Findings
    }
    $do = @{ JSON = $false; NDJSON = $false; CSV = $false; SARIF = $false }
    switch ($Format) {
        'J'      { $do.JSON   = $true }
        'JSON'   { $do.JSON   = $true }
        'N'      { $do.NDJSON = $true }
        'NDJSON' { $do.NDJSON = $true }
        'C'      { $do.CSV    = $true }
        'CSV'    { $do.CSV    = $true }
        'S'      { $do.SARIF  = $true }
        'SARIF'  { $do.SARIF  = $true }
        'A'      { $do.JSON=$do.NDJSON=$do.CSV=$do.SARIF=$true }
        'All'    { $do.JSON=$do.NDJSON=$do.CSV=$do.SARIF=$true }
        'Both'   { $do.JSON=$true }
        'HTML'   { $do.JSON=$true }  # HTML is generated by Option 21 separately
    }

    if ($do.JSON) {
        $p = Join-Path $OutputPath "wstt_findings_$stamp.json"
        $envelope | ConvertTo-Json -Depth 8 | Out-File $p -Encoding UTF8
        Write-Success "Wrote JSON: $p"
    }
    if ($do.NDJSON) {
        $p = Join-Path $OutputPath "wstt_findings_$stamp.ndjson"
        $script:Findings | ForEach-Object { $_ | ConvertTo-Json -Depth 8 -Compress } | Out-File $p -Encoding UTF8
        Write-Success "Wrote NDJSON: $p"
    }
    if ($do.CSV) {
        $p = Join-Path $OutputPath "wstt_findings_$stamp.csv"
        $script:Findings | Select-Object TimestampUtc,Severity,Category,CheckId,Host,Message |
            Export-Csv -Path $p -NoTypeInformation -Encoding UTF8
        Write-Success "Wrote CSV: $p"
    }
    if ($do.SARIF) {
        $p = Join-Path $OutputPath "wstt_findings_$stamp.sarif"
        $sevMap = @{ INFO='note'; WARN='warning'; ERROR='error'; FATAL='error'; NA='none' }
        $sarif = [pscustomobject]@{
            '$schema' = 'https://json.schemastore.org/sarif-2.1.0.json'
            version   = '2.1.0'
            runs      = @(
                [pscustomobject]@{
                    tool = [pscustomobject]@{
                        driver = [pscustomobject]@{
                            name = 'WSTT'; version = '4.0'
                            informationUri = 'https://github.com/'
                        }
                    }
                    results = @($script:Findings | ForEach-Object {
                        [pscustomobject]@{
                            ruleId  = $_.CheckId
                            level   = $sevMap[$_.Severity]
                            message = [pscustomobject]@{ text = $_.Message }
                            properties = [pscustomobject]@{ category = $_.Category; host = $_.Host }
                        }
                    })
                }
            )
        }
        $sarif | ConvertTo-Json -Depth 10 | Out-File $p -Encoding UTF8
        Write-Success "Wrote SARIF: $p"
    }
}

function Invoke-PostCheckExport {
    <#
    .SYNOPSIS
        After a check completes interactively, optionally export the captured findings.
    #>
    [CmdletBinding()] param([string]$Title = 'WSTT')
    Write-Host "`n"
    $save = Get-ValidatedChoice -Prompt "Export captured findings for '$Title'? (Y/N)" -ValidChoices @('Y','N')
    if ($save -ne 'Y') { return }
    $fmt = Get-ValidatedChoice -Prompt 'Format (J=JSON, N=NDJSON, C=CSV, S=SARIF)' -ValidChoices @('J','N','C','S')
    Export-FindingsToFile -Format $fmt -OutputPath $script:DefaultLogPath
}
